module top_module(
    alt_Q      ,
    Q_N    ,
    RESET_B,
    D      ,
    GATE
);output alt_Q      ;
    output Q_N    ;
    input  RESET_B;
    input  D      ;
    input  GATE   ;

    reg alt_Q, Q_N;

    always @(negedge RESET_B or posedge GATE) begin
        if (!RESET_B) begin
            alt_Q <= 1'b0;
            Q_N <= 1'b1;
        end else if (GATE) begin
            alt_Q <= D;
            Q_N <= ~D;
        end
    end

endmodule
